87	inline std::vector<std::string> SplitAndTrimCores(std::string_view str) {
88	
89	  if (kExternalCores) {
90	    cores_patterns = {"ax46mpv", "ax46mp", "a46mpv", "a46mp",   "ax45mp",
91	                      "a45mpv",  "a45mp",  "nx45v",  "d23v",    "ax50mpv",
92	                      "ax50mp",  "a50mpv", "a50mp"};
93	  } else {
94	    cores_patterns = {"ax46mpv", "ax46mp", "a46mpv", "a46mp",   "atomic",
95	                      "d23v",    "ax45mp", "a45mpv", "a45mp",   "nx45v",
96	                      "ax50mpv", "ax50mp", "a50mpv", "a50mp"};
97	  }
98	
99	  std::vector<std::string> substrings;
100	  std::string::size_type start = 0;
101	
102	  // Helper lambda for pattern validation
103	  auto validatePattern = [](std::string_view substr) {
104	    return std::any_of(cores_patterns.begin(), cores_patterns.end(),
105	                       [&substr](const std::string& pattern) {
106	                         return substr.find(pattern + "_") == 0;
107	                       });
108	  };
109	
110	  while (start < str.length()) {
111	    // Skip leading whitespace
112	    start = str.find_first_not_of(" \t", start);
113	    if (start == std::string::npos)
114	      break;
115	
116	    // Find end of current substring
117	    auto end = str.find(',', start);
118	    if (end == std::string::npos) {
119	      end = str.length();
120	    }
121	
122	    // Trim trailing whitespace
123	    auto trimmed_end = str.find_last_not_of(" \t", end - 1);
124	    if (trimmed_end == std::string::npos) {
125	      start = end + 1;
126	      continue;
127	    }
128	    trimmed_end++;
129	
130	    // Extract and validate substring
131	    std::string substring = std::string(str.substr(start, trimmed_end - start));
132	    if (!validatePattern(substring)) {
133	      std::ostringstream error_msg;
134	      error_msg << "The provided IP value '" << substring
135	                << "' is not supported. Please use one of the following "
136	                   "permitted values: ";
137	      for (size_t i = 0; i < cores_patterns.size(); ++i) {
138	        error_msg << "'" << cores_patterns[i] << "'";
139	        if (i < cores_patterns.size() - 1) {
140	          error_msg << ", ";
141	        }
142	      }
143	      error_msg << ".";
144	      throw ConfigError(error_msg.str());
145	    }
146	
147	    substrings.push_back(substring);
148	    start = end + 1;
149	  }
