21	class Interface {
22	 public:
23	  Module* const module = nullptr;
24	  const bool is_initiator;
25	  const std::string name;
26	  std::vector<afw::BasePort*> out_port_list;
27	  std::vector<afw::BasePort*> in_port_list;
28	
29	  static void Connect(Interface& intf1, Interface& intf2) {
30	    // type checking
31	    if (typeid(intf1) != typeid(intf2)) {
32	      throw FrameworkError(intf1.name + " and " + intf2.name +
33	                           " is not same type");
34	    }
35	
36	    if (intf1.in_port_list.size() != intf2.out_port_list.size()) {
37	      throw FrameworkError(
38	          "The number of ports in the " + fmt::format(intf1.module->name()) +
39	          "." + intf1.name + "(" + fmt::to_string(intf1.in_port_list.size()) +
40	          ") and " + fmt::format(intf2.module->name()) + "." + intf2.name +
41	          "(" + fmt::to_string(intf2.out_port_list.size()) + ") is not equal");
42	    }
43	
44	    if (intf1.out_port_list.size() != intf2.in_port_list.size()) {
45	      throw FrameworkError(
46	          "The number of ports in the " + fmt::format(intf1.module->name()) +
47	          "." + intf1.name + "(" + fmt::to_string(intf1.out_port_list.size()) +
48	          ") and " + fmt::format(intf2.module->name()) + "." + intf2.name +
49	          "(" + fmt::to_string(intf2.in_port_list.size()) + ") is not equal");
50	    }
51	
52	    for (std::size_t i = 0; i < intf1.in_port_list.size(); ++i) {
53	      intf1.in_port_list[i]->BasePortCastToInOutPort(intf2.out_port_list[i]);
54	    }
55	    for (std::size_t i = 0; i < intf2.in_port_list.size(); ++i) {
56	      intf2.in_port_list[i]->BasePortCastToInOutPort(intf1.out_port_list[i]);
57	    }
58	  };
59	  Interface(Module* module, std::string name, bool is_initiator)
60	      : module(module), name(std::move(name)), is_initiator(is_initiator) {}
61	};
