64	class InOutPort : public Port<std::decay_t<T>> {
65	 public:
66	  using Datatype = std::decay_t<T>;
67	  const bool is_initiator;
68	  const Interface* interface = nullptr;
69	
70	  InOutPort<T>& operator=(const Port<Datatype>& outport) {
71	    if (this->interface->is_initiator ==
72	        this->is_initiator) {  // Not a data provider
73	      throw FrameworkError(fmt::to_string(interface->module->name()) + "." +
74	                           this->name + " not a data provider");
75	    }
76	    this->port = &outport;
77	    return *this;
78	  }
79	
80	  InOutPort(Interface* interface, std::string name, const bool is_initiator)
81	      : Port<Datatype>(interface->module,
82	                       fmt::format("{}.{}", interface->name, name)),
83	        is_initiator(is_initiator),
84	        interface(interface) {
85	
86	    if (is_initiator ^ interface->is_initiator) {
87	      interface->out_port_list.emplace_back(this);
88	    } else {
89	      interface->in_port_list.emplace_back(this);
90	    }
91	
92	    port_list.emplace_back(this);
93	  };
94	
95	  InOutPort() = delete;
96	
97	 protected:
98	  void BasePortCastToInOutPort(BasePort* port_in) final {
99	    this->port = dynamic_cast<Port<Datatype>*>(port_in);
100	  };

