14	inline bool IsValidLogLevel(const std::string& level) {
15	
16	  std::string lower_case_level = level;
17	  std::transform(lower_case_level.begin(), lower_case_level.end(),
18	                 lower_case_level.begin(),
19	                 [](unsigned char letter) { return std::tolower(letter); });
20	
21	  static const std::unordered_set<std::string> kValidLevels = {
22	      "trace", "debug", "info", "warn", "error"};
23	
24	  return kValidLevels.find(lower_case_level) != kValidLevels.end();
25	}
