137	
138	    for (auto& module : local_module_list) {
139	      module->Init();
140	    }
141	
142	    Connect();
143	
144	    for (auto& port : local_port_list) {
145	      port->Resolve();
146	    }
147	
148	    afw::hart_id_map = afw::PerfCounter::BuildHartIdMap(afw::perfcounter_list);
149	
150	    if constexpr (kClarity && kInternalHpm) {
151	      if (dump_db_en.get_value() && dump_hpm_en.get_value()) {
152	        tocker.interval =
153	            dump_hpm_interval_cycle.get_value() * clk.period().value();
154	        for (auto& perfcounter : local_perfcounter_list_for_core) {
155	          if (perfcounter->IsClarity()) {
156	            uint32_t hpm_id = clarity_database_handler.DefineHPM(
157	                perfcounter->basename, dump_hpm_interval_cycle.get_value(),
158	                DatabaseHandler::SamplingIntervalUnit::kCycle);
159	            perfcounter->SetHpmId(hpm_id);
160	            local_clarity_perfcounter_list.emplace_back(perfcounter);
161	          }
162	        }
163	      }
164	    }
