174	inline void Tocker::TockerThread() {
175	  while (true) {
176	    // tock phase start
177	    wait();
178	    clocktime.lastTock = sc_time_stamp();
179	    parent->afterTockerWait();
180	
181	    if constexpr (kInternalHpm || kExternalHpm) {
182	      if ((kInternalHpm && parent->args_in.internal_hpm) ||
183	          (kExternalHpm && parent->args_in.external_hpm)) {
184	        if (!hpm_dump.empty()) {
185	          for (auto tuple : hpm_dump) {
186	            if (std::get<1>(tuple) == hpm_dump::start) {
187	              afw::BasePerfCounter::PerfCountersStart(
188	                  std::get<0>(tuple), parent->args_in.internal_hpm,
189	                  parent->args_in.external_hpm);
190	            } else if (std::get<1>(tuple) == hpm_dump::end) {
191	              afw::BasePerfCounter::PerfCountersEnd(
192	                  std::get<0>(tuple), parent->args_in.internal_hpm,
193	                  parent->args_in.external_hpm);
194	            }
195	          }
196	          hpm_dump.clear();
197	        }
198	      }
199	    }
200	
201	    for (auto& state : local_state_list) {
202	      state->Tock();
203	    }
204	
205	    for (auto& wavemonitor : local_wavemonitor_list) {
206	      wavemonitor->Notify();
207	    }
208	
209	    // Clarity
210	    if constexpr (kClarity && kInternalHpm) {
211	      if (dump_db_en && dump_hpm_en && interval != 0) {
212	        if (sc_time_stamp().value() % interval == 0) {
213	          for (auto& perfcounter : local_clarity_perfcounter_list) {
214	            clarity_database_handler.SendHPM_SamplingData(
215	                perfcounter->GetHpmId(),
216	                sc_time_stamp().value() / clk.period().value(),
217	                perfcounter->GetValueClarity());
218	            perfcounter->ResetClarity();
219	          }
220	        }
221	      }
222	    }
223	
224	    tocker_e.notify();
225	  }
226	}
